VALUES
  ('fire-eq-eng-moex-00723', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，液化石油氣容器檢驗場實施檢驗應 向中央主管機關申請認可，經審查合格發給認可證書，認可證書之有效期限A年，期限屆滿B個月前得 向中央主管機關申請展延，每次展延期間C年，下列A, B, C何者正確？', '["A=1, B=1, C=1", "A=2, B=2, C=2", "A=3, B=2, C=3", "A=3, B=3, C=3"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00724', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關六類物品製造場所，其外牆或 相當於該外牆之設施外側，與廠區外鄰近場所之安全距離，下列何者正確？', '["與博物館之距離，應在30公尺以上", "與電壓超過35,000伏特之高架電線之距離，應在3公尺以上", "與爆竹煙火製造場所之距離，應在10公尺以上", "與加氣站之距離，應在20公尺以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00725', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，木材加工業作業場所及油漆作業場所等，稱為何種危險工作 場所？', '["低度", "中度", "高度", "重度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00726', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法之規定，有關公共危險物品之種類、名稱及 管制量，下列何者正確？', '["硫磺：第二類，易燃固體，管制量50公斤", "乙醛：第四類，易燃液體，管制量50公升", "動植物油類：第四類，易燃液體，管制量6,000公升", "烷基鋁：第三類，發火性液體、發火性固體及禁水性物質，管制量50公斤"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00727', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法之規定，何者應實施防火管理？①收容人數50人（含員工）之托嬰中心  ②總樓地板面積300', '["總樓地板面積350平方公尺之健身休閒中心", "總樓地板面積250平方公 尺之補習班", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00728', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關水霧滅火設備之敘述，下列何者正確？', '["水霧滅火設備之水源容量，放射區域在二區域以上者，應保持40立方公尺以上", "水霧滅火設備之水源，應連結加壓送水裝置，使用消防幫浦時，其出水量每分鐘1,000公升以上", "水霧噴頭，每一水霧噴頭之有效半徑在2.6公尺以下", "放射區域有二區域以上者，其主管管徑應在60毫米以上"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00729', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關密閉式撒水頭位置之裝置，下列何者正確？', '["密閉式撒水頭之迴水板裝設於裝置面（指樓板或天花板）下方，其間距在50公分以下", "密閉式撒水頭裝置於樑下時，迴水板與樑底之間距在30公分以下，且與樓板或天花板之間距在50公 分以下", "密閉式撒水頭裝置面，四周以淨高30公分以上之樑或類似構造體區劃包圍時，按各區劃裝置", "使用密閉式撒水頭，且風管等障礙物之寬度超過120公分時，該風管等障礙物下方，亦應設置"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00730', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，有關火警自動警報設備探測器之裝置位置，下列何者正確？', '["局限型探測器之裝置，得傾斜45度以上", "局限型探測器以裝置在探測區域周圍附近為原則", "牆上設有出風口時，應距離該出風口1.5公尺以上", "天花板設排氣口或回風口時，偵煙式探測器應裝置於排氣口或回風口周圍2公尺範圍內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00731', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防設備師及消防設備士管理辦法規定，有關消防設備師之敘述，下列何者正確？①執行業務，應備業', '["自取得證書日起每3年應接受講習一次", "直轄市、縣（市） 之消防設備師達20人以上者，得組織直轄市、縣（市）消防設備師公會", "各級消防設備師公會之組織 及活動，依人民團體法規定辦理", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00732', 'fire-eq-eng', 'fire-eq-eng-moex-104-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防安全設備檢修專業機構管理辦法之規定，有關消防安全設備檢修專業機構之敘述，下列何者正確？', '["應具備實收資本額在新臺幣500萬元以上之公司", "專任之消防設備師及消防設備士合計達10人以上， 其中消防設備師至少 2 人", "檢修機構合格證書記載事項變更時，應於 30 日內向內政部申請變更登記", "檢修機構應於年度終結後3個月內，檢具書表，報請內政部核定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:17+00:00", "source_pdf_sha1": "98bf0e3bcf7c", "answer_pdf_sha1": "d4145bb024b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "401", "s": "0702", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
